#include <bits/stdc++.h>
using namespace std;
long long C[2003][2003];
int s[2003][2003];
int main(){
    int t,k,n,m;
    cin>>t>>k;
    for(int i=0;i<=2000;i++){
        for(int j=0;j<=i;j++){
            C[i][j]=(i==0 || j==0? 1:(C[i-1][j-1]+C[i-1][j])%k);
            if(i && j)
            	s[i][j]=(!C[i][j])+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
        if(i)
        	for(int j=i+1;j<=2000;j++)
            	s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1];
    }
    while(t--){
        cin>>n>>m;
        printf("%d\n",s[n][m]);
    }
    return 0;
}
